-- beyondGREEN Professional costing catalog (separate from ERP products)
create extension if not exists pgcrypto;
create table if not exists public.professional_catalog (
  id uuid primary key default gen_random_uuid(),
  sku text,
  category text,
  description text,
  upc text,
  variation text,
  qty_case numeric,
  case_gross_wt numeric,
  case_dims text,
  case_cu_ft numeric,
  cases_pallet numeric,
  pallet_net_wt numeric,
  pallet_ht numeric,
  material text,
  hts text,
  duty_cat text,
  adcvd_scope text,
  origin text,
  mfg_type text,
  fob numeric,
  landed numeric,
  landed_unit numeric,
  win_likelihood text,
  moq text,
  notes text,
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now()
);
alter table public.professional_catalog enable row level security;
-- RLS on, no policies: anon/authenticated denied; portal server uses service-role key (bypasses RLS).

